    /**
     * Apply a differential update: stage, fetch only the changed layers
     * through `fetcher`, verify everything and swap atomically. Any
     * failure leaves the installed territory untouched; the active flag
     * is preserved.
     */
    func applyUpdate(territoryId: String, newManifestJson: String, newManifestSigBase64: String, fetcher: LayerFetcher) throws  -> UpdateResult
    
    /**
     * Check the signed channel index for an update to an installed
     * territory. `index_json` must be the exact bytes served as
     * `index.json` and `index_sig_base64` the content of
     * `index.json.sig`; the remote manifest is fetched and verified
     * through `fetcher`. Returns `None` when the device is already on
     * the channel's latest version (or the channel does not list the
     * territory).
     */
    func checkForUpdate(territoryId: String, indexJson: String, indexSigBase64: String, fetcher: LayerFetcher) throws  -> AvailableUpdate?
    
    /**
     * Install an unpacked package directory.
     */
    func installDir(packageDir: String) throws  -> TerritoryInfo
    
    /**
     * Install a packed `.snpkg` archive (verify-then-promote; rejected
     * packages leave no trace).
     */
    func installSnpkg(archivePath: String) throws  -> TerritoryInfo
    
    /**
     * Absolute path of a layer inside an installed territory (e.g. the
     * Valhalla tile tree for valhalla-mobile, the PMTiles file for
     * MapLibre).
     */
    func layerPath(territoryId: String, kind: MapLayerKind) throws  -> String
    
    /**
     * List installed territories in territory-id order.
     */
    func list() throws  -> [TerritoryInfo]
    
    /**
     * Plan a differential update from the installed manifest to
     * `new_manifest_json` (a signed manifest's JSON body, as served by
     * the update channel).
     */
    func planUpdate(newManifestJson: String) throws  -> UpdatePlan
    
    /**
     * Remove an installed territory (clears the active marker if needed).
     */
    func remove(territoryId: String) throws 
    
    /**
     * Mark a territory as active (persisted atomically).
     */
    func setActive(territoryId: String) throws 
    
}
