 * [`sn_adr::AdrVehicleProfile`]. Defaults are the EU maximum authorised
 * dimensions (Council Directive 96/53/EC) with no dangerous goods.
 */
public struct AdrProfile: Equatable, Hashable {
    /**
     * Vehicle height in metres.
     */
    public var heightM: Double
    /**
     * Vehicle width in metres.
     */
    public var widthM: Double
    /**
     * Vehicle length in metres.
     */
    public var lengthM: Double
    /**
     * Gross combination weight in metric tonnes.
     */
    public var grossWeightT: Double
    /**
     * Heaviest single-axle load in tonnes, if known.
     */
    public var axleLoadT: Double?
    /**
     * Number of axles, if known.
     */
    public var axleCount: UInt32?
    /**
     * Whether the vehicle carries dangerous goods at all.
     */
    public var hazmat: Bool
    /**
     * Declared ADR tunnel restriction code. `None` with `hazmat = true`
     * means "dangerous goods of unknown code" and is treated as code B
     * (most restrictive non-quantity code).
     */
    public var tunnelCode: AdrTunnelCode?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Vehicle height in metres.
         */heightM: Double = Double(4.0), 
        /**
         * Vehicle width in metres.
         */widthM: Double = Double(2.55), 
        /**
         * Vehicle length in metres.
         */lengthM: Double = Double(16.5), 
        /**
         * Gross combination weight in metric tonnes.
         */grossWeightT: Double = Double(40.0), 
        /**
         * Heaviest single-axle load in tonnes, if known.
         */axleLoadT: Double? = nil, 
        /**
         * Number of axles, if known.
         */axleCount: UInt32? = nil, 
        /**
         * Whether the vehicle carries dangerous goods at all.
         */hazmat: Bool = false, 
        /**
         * Declared ADR tunnel restriction code. `None` with `hazmat = true`
         * means "dangerous goods of unknown code" and is treated as code B
         * (most restrictive non-quantity code).
         */tunnelCode: AdrTunnelCode? = nil) {
        self.heightM = heightM
        self.widthM = widthM
        self.lengthM = lengthM
        self.grossWeightT = grossWeightT
        self.axleLoadT = axleLoadT
        self.axleCount = axleCount
        self.hazmat = hazmat
        self.tunnelCode = tunnelCode
    }

    

    
}

