// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * The guidance state reported after each location update, flattened for
 * FFI from Ferrostar's `TripState`.
 *
 * The `Navigating` variant is deliberately larger than the others: it is
 * the steady-state payload and the FFI shape (UniFFI enums cannot box),
 * and one allocation per location fix is irrelevant next to the fix
 * cadence.
 */

public enum GuidanceUpdate: Equatable, Hashable {
    
    /**
     * Actively navigating.
     */
    case navigating(
        /**
         * Zero-based index of the current step within the route.
         */stepIndex: UInt32, 
        /**
         * Distance to the next maneuver in metres.
         */distanceToNextManeuverM: Double, 
        /**
         * Total distance remaining in the trip, in metres.
         */distanceRemainingM: Double, 
        /**
         * Total duration remaining in the trip, in seconds.
         */durationRemainingS: Double, 
        /**
         * Written instruction for the current step.
         */currentInstruction: String, 
        /**
         * Deviation from the current step line in metres, when the user
         * is off the current step but still on the route polyline.
         */deviationM: Double?, 
        /**
         * Visual banner for the upcoming maneuver, when one is active at
         * the current distance.
         */visual: VisualBanner?, 
        /**
         * Spoken prompt currently due; platform layers must de-duplicate
         * by `utterance_id` before synthesising.
         */spoken: SpokenPrompt?, 
        /**
         * Route-snapped position and course. Drive follow-cameras from
         * this, never the raw fix. `Option` only for enum-shape
         * stability — Ferrostar always reports it while navigating.
         */snapped: SnappedFix?, 
        /**
         * Urgency of the current step's instruction (see
         * [`InstructionSeverity`] for the derivation). Voice layers key
         * prosody and earcons off this.
         */severity: InstructionSeverity
    )
    /**
     * The user has arrived at the destination.
     */
    case arrived
    /**
     * The user has left the route entirely (beyond the configured
     * deviation threshold from every remaining step). The platform layer
     * should recalculate.
     */
    case offRoute(
        /**
         * Deviation from the route line in metres.
         */deviationM: Double
    )





}

#if compiler(>=6)
extension GuidanceUpdate: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeGuidanceUpdate: FfiConverterRustBuffer {
    typealias SwiftType = GuidanceUpdate

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> GuidanceUpdate {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .navigating(stepIndex: try FfiConverterUInt32.read(from: &buf), distanceToNextManeuverM: try FfiConverterDouble.read(from: &buf), distanceRemainingM: try FfiConverterDouble.read(from: &buf), durationRemainingS: try FfiConverterDouble.read(from: &buf), currentInstruction: try FfiConverterString.read(from: &buf), deviationM: try FfiConverterOptionDouble.read(from: &buf), visual: try FfiConverterOptionTypeVisualBanner.read(from: &buf), spoken: try FfiConverterOptionTypeSpokenPrompt.read(from: &buf), snapped: try FfiConverterOptionTypeSnappedFix.read(from: &buf), severity: try FfiConverterTypeInstructionSeverity.read(from: &buf)
        )
        
        case 2: return .arrived
        
        case 3: return .offRoute(deviationM: try FfiConverterDouble.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: GuidanceUpdate, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .navigating(stepIndex,distanceToNextManeuverM,distanceRemainingM,durationRemainingS,currentInstruction,deviationM,visual,spoken,snapped,severity):
            writeInt(&buf, Int32(1))
            FfiConverterUInt32.write(stepIndex, into: &buf)
            FfiConverterDouble.write(distanceToNextManeuverM, into: &buf)
            FfiConverterDouble.write(distanceRemainingM, into: &buf)
            FfiConverterDouble.write(durationRemainingS, into: &buf)
            FfiConverterString.write(currentInstruction, into: &buf)
            FfiConverterOptionDouble.write(deviationM, into: &buf)
            FfiConverterOptionTypeVisualBanner.write(visual, into: &buf)
            FfiConverterOptionTypeSpokenPrompt.write(spoken, into: &buf)
            FfiConverterOptionTypeSnappedFix.write(snapped, into: &buf)
            FfiConverterTypeInstructionSeverity.write(severity, into: &buf)
            
        
        case .arrived:
            writeInt(&buf, Int32(2))
        
        
        case let .offRoute(deviationM):
            writeInt(&buf, Int32(3))
            FfiConverterDouble.write(deviationM, into: &buf)
            
        }
    }
}


