    case Routing(
        /**
         * Human-readable description.
         */message: String
    )
    /**
     * Guidance session failure.
     */
    case Guidance(
        /**
         * Human-readable description.
         */message: String
    )
    /**
     * A caller-supplied argument was invalid.
     */
    case InvalidArgument(
        /**
         * Human-readable description.
         */message: String
    )

    

    

    
